input.sql:
-- Delete exact content dupes, keeping the highest importance version of each
DELETE FROM public.omega_memory_entries
WHERE id IN (
  SELECT id FROM (
    SELECT id,
      ROW_NUMBER() OVER (PARTITION BY content ORDER BY importance DESC, created_at DESC) as rn
    FROM public.omega_memory_entries
  ) ranked
  WHERE rn > 1
);

